S RingAlloc {
    buf: [u8]~,
    head: usize,
    size: usize,
    cap: usize,
}

I RingAlloc {
    +f new(cap: usize) -> RingAlloc {
        m buf: [u8]~ = [];
        m i: usize = 0;
        loop { ? i >= cap { break; } buf.push(0); i = i + 1; }
        @RingAlloc { buf: buf, head: 0, size: 0, cap: cap }
    }
    +f alloc(&!self, n: usize) -> ?usize {
        ? self.size + n > self.cap { ret ?None; }
        v offset = (self.head + self.size) % self.cap;
        self.size = self.size + n;
        ?Some(offset)
    }
    +f free(&!self, n: usize) {
        v actual = ? n > self.size { self.size } : { n };
        self.head = (self.head + actual) % self.cap;
        self.size = self.size - actual;
    }
    +f available(&self) -> usize { self.cap - self.size }
}

rust_equivalent.rs_source:
struct RingAlloc { buf: Vec<u8>, head: usize, size: usize, cap: usize }

impl RingAlloc {
    pub fn new(cap: usize) -> Self { Self { buf: vec![0; cap], head: 0, size: 0, cap } }
    pub fn alloc(&mut self, n: usize) -> Option<usize> {
        if self.size + n > self.cap { return None; }
        let offset = (self.head + self.size) % self.cap;
        self.size += n;
        Some(offset)
    }
    pub fn free(&mut self, n: usize) {
        let actual = n.min(self.size);
        self.head = (self.head + actual) % self.cap;
        self.size -= actual;
    }
    pub fn available(&self) -> usize { self.cap - self.size }
}

