S BitVec { data: [u64]~, len: usize }

I BitVec {
    +f new(n: usize) -> BitVec {
        v words = (n + 63) / 64;
        m data: [u64]~ = [];
        m i: usize = 0;
        loop { ? i >= words { break; } data.push(0); i = i + 1; }
        @BitVec { data: data, len: n }
    }
    +f set(&!self, idx: usize) {
        self.data[idx / 64] = self.data[idx / 64] | (1 << (idx % 64));
    }
    +f clear(&!self, idx: usize) {
        self.data[idx / 64] = self.data[idx / 64] & !(1 << (idx % 64));
    }
    +f get(&self, idx: usize) -> bool {
        (self.data[idx / 64] >> (idx % 64)) & 1 == 1
    }
    +f count_ones(&self) -> usize {
        m total: usize = 0;
        @ word : &self.data { total = total + word.count_ones() as usize; }
        total
    }
}

