struct BitVec { data: Vec<u64>, len: usize }

impl BitVec {
    pub fn new(n: usize) -> Self { Self { data: vec![0; (n + 63) / 64], len: n } }
    pub fn set(&mut self, idx: usize) { self.data[idx / 64] |= 1u64 << (idx % 64); }
    pub fn clear(&mut self, idx: usize) { self.data[idx / 64] &= !(1u64 << (idx % 64)); }
    pub fn get(&self, idx: usize) -> bool { (self.data[idx / 64] >> (idx % 64)) & 1 == 1 }
    pub fn count_ones(&self) -> usize { self.data.iter().map(|w| w.count_ones() as usize).sum() }
}

