struct ByteBuf { data: Vec<u8>, read_pos: usize, write_pos: usize }

impl ByteBuf {
    pub fn new() -> Self { Self { data: Vec::new(), read_pos: 0, write_pos: 0 } }
    pub fn write_u8(&mut self, val: u8) { self.data.push(val); self.write_pos += 1; }
    pub fn write_u32_be(&mut self, val: u32) {
        self.write_u8((val >> 24) as u8);
        self.write_u8((val >> 16) as u8);
        self.write_u8((val >> 8) as u8);
        self.write_u8(val as u8);
    }
    pub fn read_u8(&mut self) -> Option<u8> {
        if self.read_pos >= self.write_pos { return None; }
        let val = self.data[self.read_pos];
        self.read_pos += 1;
        Some(val)
    }
    pub fn remaining(&self) -> usize { self.write_pos - self.read_pos }
}

