S LruCache[V] {
    map: {s: V},
    order: [s]~,
    cap: usize,
}

I LruCache[V] {
    +f new(cap: usize) -> LruCache[V] {
        @LruCache { map: {}, order: [], cap: cap }
    }
    +f get(&!self, key: &s) -> ?&V {
        ? self.map.contains_key(key) {
            self.touch(key);
            self.map.get(key)
        } : { ?None }
    }
    +f put(&!self, key: s, val: V) {
        ? self.map.contains_key(&key) {
            self.touch(&key);
            self.map.insert(key, val);
        } : {
            ? self.order.len() >= self.cap {
                v evict = self.order.remove(0);
                self.map.remove(&evict);
            }
            self.order.push(key.clone());
            self.map.insert(key, val);
        }
    }
    f touch(&!self, key: &s) {
        v idx = self.order.iter().position(fn(k) => k == key);
        ? idx { ?Some(i) => { self.order.remove(i); self.order.push(key.clone()); }, ?None => {} }
    }
}

