use std::env;

struct EnvConfig { port: u16, host: String, debug: bool }

pub fn load_config() -> Result<EnvConfig, String> {
    let port: u16 = env::var("PORT").unwrap_or_else(|_| "8080".into())
        .parse().map_err(|e: std::num::ParseIntError| format!("bad PORT: {}", e))?;
    let host = env::var("HOST").unwrap_or_else(|_| "localhost".into());
    let debug = env::var("DEBUG").unwrap_or_else(|_| "false".into()) == "true";
    Ok(EnvConfig { port, host, debug })
}

