S CliArgs {
    flags: [s]~,
    opts: {s: s},
    positional: [s]~,
}

+f parse_args(args: [s]~) -> CliArgs {
    m flags: [s]~ = [];
    m opts: {s: s} = {};
    m positional: [s]~ = [];
    m i: usize = 0;
    loop {
        ? i >= args.len() { break; }
        v arg = &args[i];
        ? arg.starts_with("--") {
            v key = arg[2..];
            ? i + 1 < args.len() && !args[i+1].starts_with("-") {
                opts.insert(key.to_string(), args[i+1].clone());
                i = i + 2;
            } : {
                flags.push(key.to_string());
                i = i + 1;
            }
        } : {
            positional.push(arg.clone());
            i = i + 1;
        }
    }
    @CliArgs { flags: flags, opts: opts, positional: positional }
}

