use std::collections::HashMap;

struct CliArgs { flags: Vec<String>, opts: HashMap<String, String>, positional: Vec<String> }

pub fn parse_args(args: Vec<String>) -> CliArgs {
    let mut flags = Vec::new();
    let mut opts = HashMap::new();
    let mut positional = Vec::new();
    let mut i = 0;
    while i < args.len() {
        if args[i].starts_with("--") {
            let key = args[i][2..].to_string();
            if i + 1 < args.len() && !args[i+1].starts_with("-") {
                opts.insert(key, args[i+1].clone());
                i += 2;
            } else {
                flags.push(key);
                i += 1;
            }
        } else {
            positional.push(args[i].clone());
            i += 1;
        }
    }
    CliArgs { flags, opts, positional }
}

