S Logger {
    min_level: LogLevel,
    prefix: s,
}

I Logger {
    +f new(level: LogLevel, prefix: s) -> Logger {
        @Logger { min_level: level, prefix: prefix }
    }
    +f log(&self, level: LogLevel, msg: &s) / io {
        ? level >= self.min_level {
            v level_str = ? level {
                LogLevel.Trace => "TRACE",
                LogLevel.Debug => "DEBUG",
                LogLevel.Info => "INFO",
                LogLevel.Warn => "WARN",
                LogLevel.Error => "ERROR",
            };
            io.write_line(f"[{self.prefix}] [{level_str}] {msg}");
        }
    }
    +f info(&self, msg: &s) / io { self.log(LogLevel.Info, msg); }
    +f error(&self, msg: &s) / io { self.log(LogLevel.Error, msg); }
}

