#[derive(PartialEq, PartialOrd)]
enum LogLevel { Trace, Debug, Info, Warn, Error }

struct Logger { min_level: LogLevel, prefix: String }

impl Logger {
    pub fn new(level: LogLevel, prefix: String) -> Self { Self { min_level: level, prefix } }
    pub fn log(&self, level: LogLevel, msg: &str) {
        if level >= self.min_level {
            let level_str = match level {
                LogLevel::Trace => "TRACE", LogLevel::Debug => "DEBUG",
                LogLevel::Info => "INFO", LogLevel::Warn => "WARN",
                LogLevel::Error => "ERROR",
            };
            eprintln!("[{}] [{}] {}", self.prefix, level_str, msg);
        }
    }
    pub fn info(&self, msg: &str) { self.log(LogLevel::Info, msg); }
    pub fn error(&self, msg: &str) { self.log(LogLevel::Error, msg); }
}
